import { useNavigate } from "react-router-dom";
import "./Dashboard.css";

function Dashboard() {
  const navigate = useNavigate();
  const name = localStorage.getItem("name") || "Patient";

  const logout = () => {
    localStorage.clear();
    navigate("/login");
  };

  return (
    <div className="dashboard-container">
      <h1>👩‍⚕️ Doctor-AI</h1>
      <p className="welcome">Hello <b>{name}</b>, how can I help you today?</p>

      <div className="card-grid">
        <div className="card" onClick={() => navigate("/vitals")}>
          🧪
          <h3>Enter Vitals</h3>
          <p>Add glucose, BP, heart rate, SpO₂</p>
        </div>

        <div className="card" onClick={() => navigate("/consult")}>
          🩺
          <h3>Consult Doctor</h3>
          <p>Chat with Doctor-AI</p>
        </div>

        <div className="card" onClick={() => navigate("/profile")}>
          👤
          <h3>Profile</h3>
          <p>Update age, height, weight</p>
        </div>

        <div className="card disabled">
          📜
          <h3>History</h3>
          <p>Coming soon</p>
        </div>
      </div>

      <button className="logout-btn" onClick={logout}>
        🚪 Logout
      </button>
    </div>
  );
}

export default Dashboard;
